// Architecture Outline Generation
// Produces a high-level system architecture for the project.
// In production, this node would be replaced with an LLM call.
const { projectId, stageKey, executionId, subStage, context } = $input.first().json.body;

const architectureOutline = {
  systemOverview: "A cloud-native SaaS platform built on a modular microservices architecture. The system separates concerns into an API gateway, core business logic services, an event bus for async communication, and a persistence layer with read/write separation. Designed for horizontal scalability and independent service deployment.",
  components: [
    {
      name: "API Gateway",
      responsibility: "Request routing, authentication, rate limiting, and API versioning",
      technology: "Node.js with Express, nginx reverse proxy"
    },
    {
      name: "Core Service",
      responsibility: "Business logic, domain model enforcement, and workflow orchestration",
      technology: "Node.js with TypeScript, Domain-Driven Design patterns"
    },
    {
      name: "Event Bus",
      responsibility: "Async event distribution, saga orchestration, and cross-service communication",
      technology: "Redis Streams with dead-letter queue support"
    },
    {
      name: "Data Layer",
      responsibility: "Persistent storage with CQRS read/write separation",
      technology: "PostgreSQL (write), Redis (read cache), S3 (blob storage)"
    },
    {
      name: "Dashboard UI",
      responsibility: "Operator interface for monitoring, configuration, and manual overrides",
      technology: "React with Vite, TanStack Query for server state"
    }
  ],
  dataFlow: "Client requests enter through the API Gateway, which authenticates and routes to the appropriate Core Service. Services emit domain events to the Event Bus for async processing. The Data Layer handles persistence with write-ahead logging to PostgreSQL and read-through caching via Redis. The Dashboard UI connects via REST APIs and SSE for real-time updates.",
  deploymentModel: "Containerized deployment via Docker Compose for development, with Kubernetes manifests for production. CI/CD pipeline builds, tests, and deploys each service independently. Blue-green deployment strategy with automatic rollback on health check failure.",
  recommendation: "Proceed with the modular architecture. Start with a monolithic deployment (single container) and extract services as complexity warrants. This avoids premature distribution overhead while maintaining clean module boundaries."
};

return {
  json: {
    projectId,
    stageKey,
    executionId,
    subStage: subStage || 'architecture_outline',
    architectureResult: architectureOutline
  }
};
